  Future<String> _s3PutObject({
    required String bucket,
    required String region,
    required String key,
    required Uint8List body,
    required String contentType,
  }) async {
    final host = (region == 'us-east-1')
        ? '$bucket.s3.amazonaws.com'
        : '$bucket.s3.$region.amazonaws.com';

    final uri = Uri.https(host, '/$key');

    final now = DateTime.now().toUtc();
    final amzDate = _formatAmzDate(now);
    final dateStamp = _formatDateStamp(now);

    final payloadHash = sha256.convert(body).toString();

    final headers = <String, String>{
      'host': host,
      'x-amz-content-sha256': payloadHash,
      'x-amz-date': amzDate,
      'content-type': contentType,
      'content-length': body.length.toString(),
    };

    final signedHeaders = _signedHeaders(headers);
    final canonicalHeaders = _canonicalHeaders(headers);

    final canonicalRequest = [
      'PUT',
      uri.path,
      '', // query
      canonicalHeaders,
      signedHeaders,
      payloadHash,
    ].join('\n');

    final canonicalRequestHash = sha256.convert(utf8.encode(canonicalRequest)).toString();

    final credentialScope = '$dateStamp/$region/s3/aws4_request';
    final stringToSign = [
      'AWS4-HMAC-SHA256',
      amzDate,
      credentialScope,
      canonicalRequestHash,
    ].join('\n');

    final signingKey = _getSignatureKey(awsSecretAccessKey, dateStamp, region, 's3');
    final signature = _hmacHex(signingKey, utf8.encode(stringToSign));

    final authorization =
        'AWS4-HMAC-SHA256 Credential=$awsAccessKeyId/$credentialScope, SignedHeaders=$signedHeaders, Signature=$signature';

    final reqHeaders = Map<String, String>.from(headers);
    reqHeaders['Authorization'] = authorization;

    final resp = await http.put(uri, headers: reqHeaders, body: body);

    if (resp.statusCode < 200 || resp.statusCode >= 300) {
      throw 'S3 PUT failed (${resp.statusCode}): ${resp.body}';
    }

    return uri.toString();
  }

  String _formatAmzDate(DateTime dt) {
    String two(int v) => v.toString().padLeft(2, '0');
    return '${dt.year}${two(dt.month)}${two(dt.day)}T${two(dt.hour)}${two(dt.minute)}${two(dt.second)}Z';
  }

  String _formatDateStamp(DateTime dt) {
    String two(int v) => v.toString().padLeft(2, '0');
    return '${dt.year}${two(dt.month)}${two(dt.day)}';
  }

  String _canonicalHeaders(Map<String, String> headers) {
    final keys = headers.keys.map((k) => k.toLowerCase()).toList()..sort();
    final b = StringBuffer();
    for (final k in keys) {
      final v = headers.entries.firstWhere((e) => e.key.toLowerCase() == k).value;
      b.write('$k:${v.trim().replaceAll(RegExp(r'\s+'), ' ')}\n');
    }
    return b.toString();
  }

  String _signedHeaders(Map<String, String> headers) {
    final keys = headers.keys.map((k) => k.toLowerCase()).toList()..sort();
    return keys.join(';');
  }

  List<int> _hmac(List<int> key, List<int> message) {
    final h = Hmac(sha256, key);
    return h.convert(message).bytes;
  }

  String _hmacHex(List<int> key, List<int> message) {
    final h = Hmac(sha256, key);
    return h.convert(message).toString();
  }

  List<int> _getSignatureKey(String key, String dateStamp, String regionName, String serviceName) {
    final kDate = _hmac(utf8.encode('AWS4$key'), utf8.encode(dateStamp));
    final kRegion = _hmac(kDate, utf8.encode(regionName));
    final kService = _hmac(kRegion, utf8.encode(serviceName));
    final kSigning = _hmac(kService, utf8.encode('aws4_request'));
    return kSigning;
  }
